<!-- pages/orderDetails/orderDetails.vue -->
<template>
	<view class="container">
		<div class="box2">
			<!-- 标题 -->
			<Mtitle title="订单详情"></Mtitle>

			<view class="box">
				<!-- 加载中 -->
				<view v-if="!orderData" style="text-align: center; padding: 20px;">
					<text>加载中...</text>
				</view>

				<!-- 订单详情 -->
				<view v-else class="detail-content">
					<orderDetail v-if="orderData.order_id" :order_id="orderData.order_id"
						:status="orderData.order_status" :product="orderData.product_id" :number='orderData.quantity'
						:singlePrice='orderData.unit_price' :startDate='orderData.created_at'
						:endDate="orderData.end_at" :totalPrice='orderData.total_price' />
					<personalCard class="pCard" v-if="orderData.order_id" :name="userInfo.username" :uid="userInfo.uid"
						:content="userInfo.bio || '暂无简介'">
					</personalCard>
				</view>

				<!-- 订单不存在 -->
				<view v-if="orderData === null" style="text-align: center; color: #999; padding: 20px;">
					<text>订单不存在或加载失败</text>
				</view>
			</view>
		</div>
	</view>
</template>

<script setup>
	// ✅ 正确导入 uni-app 的生命周期钩子
	import {
		decodeToken // ✅ 正确导入
	} from '@/utils/jwt.js'
	import {
		ref
	} from 'vue'
	import {
		onLoad
	} from '@dcloudio/uni-app'

	// 响应式数据
	const loading = ref(true)
	const orderData = ref(null)
	const userInfo = ref({})

	// ✅ 使用 onLoad 钩子
	onLoad(async (options) => {
		const orderId = options.orderId
		console.log('✅ 接收到的 orderId:', orderId)

		if (!orderId) {
			uni.showToast({
				title: '缺少订单ID',
				icon: 'none'
			})
			return
		}

		// 调用获取订单详情
		await getOrderDetail(orderId)
		await getUserInfo()
	})

	// 获取订单详情
	const getOrderDetail = async (orderId) => {
		const token = uni.getStorageSync('token')
		if (!token) {
			uni.showToast({
				title: '请先登录',
				icon: 'none'
			})
			return
		}

		try {
			const res = await uni.request({
				url: `http://localhost:5000/api/orders/orderss/${orderId}`,
				method: 'GET',
				header: {
					'Authorization': `Bearer ${token}`,
					'Content-Type': 'application/json'
				}
			})

			if (res.statusCode === 200) {
				const data = res.data

				// ✅ 判断是否是数组（调试用）
				if (Array.isArray(data)) {
					console.warn('⚠️ 后端返回了数组，但预期是对象:', data)
					// 尝试匹配 order_id
					const matched = data.find(item => item.order_id === orderId)
					if (matched) {
						orderData.value = matched
					} else {
						uni.showToast({
							title: '订单未找到',
							icon: 'none'
						})
					}
				} else {
					orderData.value = data // ✅ 正常对象
				}
			} else {
				uni.showToast({
					title: res.data.message || '加载失败',
					icon: 'none'
				})
			}
		} catch (error) {
			console.error('❌ 请求订单详情失败:', error)
			uni.showToast({
				title: '网络错误',
				icon: 'none'
			})
		}
	}

	// 获取用户信息
	const getUserInfo = async () => {
		loading.value = true

		try {
			const token = uni.getStorageSync('token')
			const decoded = decodeToken(token)
			if (!decoded) return
			// const userId = decoded.userId || decoded.uid || decoded.id
			const userId = orderData.value.creator_uid
			if (!token) {
				uni.showToast({
					title: '请先登录',
					icon: 'none'
				})
				return
			}

			const res = await uni.request({
				url: `http://localhost:5000/api/users/public/${userId}`,
				method: 'GET',
				header: {
					'Authorization': `Bearer ${token}`,
					'Content-Type': 'application/json'
				}
			})

			if (res.statusCode === 200) {
				userInfo.value = res.data
				// console.log('orderData:', orderData.value)
				console.log('用户信息:', res.data)
			} else {
				uni.showToast({
					title: res.data.message || '获取失败',
					icon: 'none'
				})
			}
		} catch (error) {
			console.error('获取用户信息失败:', error)
			uni.showToast({
				title: '网络错误',
				icon: 'none'
			})
		} finally {
			loading.value = false
		}
	}
</script>
<style scoped>
	.pCard {
		margin-top: 10px;
	}

	.container {
		background-image: url('@/static/images/background(light)/OIP-C.jpg');
		background-size: cover;
		background-position: center center;
		background-repeat: no-repeat;
		background-attachment: fixed;
		width: 100%;
		height: 100vh;
	}

	.detail-card {
		background-color: rgba(255, 255, 255, 0.9);
		border-radius: 20rpx;
		padding: 30rpx;
		margin-bottom: 30rpx;
		font-size: 28rpx;
		line-height: 1.6;
	}

	.box {
		/* border: solid 1px red; */
	}

	.box2 {
		/* border: solid 1px blue; */
	}

	.detail-content {
		/* border: solid 1px black; */
	}

	.detail-card p {
		margin: 10rpx 0;
	}
</style>